// Generated by forge proof from worktree-repair.md
import { describe, test, expect, beforeAll, afterAll, beforeEach, afterEach } from 'bun:test';
import { promises as fs } from 'fs';
import path from 'path';
import os from 'os';
import { exec } from 'child_process';
import { promisify } from 'util';
import { setupHermeticGit, teardownHermeticGit } from './test-utils.js';
import {
  getTestDb,
  insertWorktree,
  getWorktree,
  listWorktrees,
  updateWorktreeStatus,
} from './db.js';
import type { Database } from 'bun:sqlite';

const execAsync = promisify(exec);

// ── Hermetic Git ─────────────────────────────────────────────

beforeAll(() => { setupHermeticGit(); });
afterAll(() => { teardownHermeticGit(); });

// ── Helpers ──────────────────────────────────────────────────

let tmpDir: string;
let repoDir: string;
let db: Database;

function makeId(): string {
  return `wt-${Date.now()}-${Math.random().toString(16).substring(2, 8)}`;
}

async function createTestRepo(): Promise<string> {
  const dir = await fs.mkdtemp(path.join(os.tmpdir(), 'forge-repair-test-'));
  const repo = path.join(dir, 'project');
  await fs.mkdir(repo, { recursive: true });
  await execAsync('git init', { cwd: repo });
  await execAsync('git config user.email "test@test.com"', { cwd: repo });
  await execAsync('git config user.name "Test"', { cwd: repo });
  await fs.writeFile(path.join(repo, 'README.md'), '# Test Project');
  await execAsync('git add . && git commit -m "init"', { cwd: repo });
  return repo;
}

beforeEach(async () => {
  db = getTestDb();
  repoDir = await createTestRepo();
  tmpDir = path.dirname(repoDir);
});

afterEach(async () => {
  // Clean up all worktrees first
  try {
    const { stdout } = await execAsync('git worktree list --porcelain', { cwd: repoDir });
    const paths: string[] = [];
    for (const line of stdout.split('\n')) {
      if (line.startsWith('worktree ') && !line.includes(repoDir)) {
        paths.push(line.substring('worktree '.length));
      }
    }
    for (const p of paths) {
      try { await execAsync(`git worktree remove "${p}" --force`, { cwd: repoDir }); } catch { /* ignore */ }
    }
  } catch { /* ignore */ }
  await fs.rm(tmpDir, { recursive: true, force: true });
});

// ── Missing directory detection ─────────────────────────────

describe('repair: missing directory detection', () => {
  test('detects registry entry pointing to non-existent directory', () => {
    const id = makeId();
    insertWorktree(db, {
      id,
      spec_path: 'specs/missing.md',
      branch: 'forge/missing',
      worktree_path: '/tmp/this-path-does-not-exist-ever',
      status: 'created',
    });

    const wt = getWorktree(db, id)!;
    expect(wt).not.toBeNull();

    // In repair, this would be detected as missing_directory
    const dirExists = Bun.file(wt.worktree_path).size > 0;
    expect(dirExists).toBe(false);
  });

  test('marks missing directory worktree as failed with --fix', () => {
    const id = makeId();
    insertWorktree(db, {
      id,
      spec_path: 'specs/gone.md',
      branch: 'forge/gone',
      worktree_path: '/tmp/nonexistent-wt-dir',
      status: 'complete',
    });

    // Simulate repair --fix behavior
    updateWorktreeStatus(db, id, 'failed', 'Directory missing from filesystem');

    const wt = getWorktree(db, id)!;
    expect(wt.status).toBe('failed');
    expect(wt.error).toBe('Directory missing from filesystem');
  });

  test('skips cleaned worktrees (directory removal is expected)', () => {
    const id = makeId();
    insertWorktree(db, {
      id,
      spec_path: 'specs/cleaned.md',
      branch: 'forge/cleaned',
      worktree_path: '/tmp/cleaned-dir',
      status: 'created',
    });
    // Walk to cleaned
    updateWorktreeStatus(db, id, 'cleaned');

    const wt = getWorktree(db, id)!;
    // In repair logic: if (w.status === 'cleaned') continue;
    expect(wt.status).toBe('cleaned');
  });
});

// ── Git worktree deregister detection ───────────────────────

describe('repair: git deregister detection', () => {
  test('detects directory exists but not in git worktree list', async () => {
    // Create a real worktree
    const branch = 'forge/deregister-test';
    await execAsync(`git branch "${branch}"`, { cwd: repoDir });
    const worktreePath = path.join(tmpDir, 'project-deregister');
    await execAsync(`git worktree add "${worktreePath}" "${branch}"`, { cwd: repoDir });

    // Verify it's in the list
    const { stdout: before } = await execAsync('git worktree list --porcelain', { cwd: repoDir });
    expect(before).toContain(worktreePath);

    // Remove it from git tracking (simulating deregister)
    await execAsync(`git worktree remove "${worktreePath}" --force`, { cwd: repoDir });

    // Recreate the directory manually (simulating orphan)
    await fs.mkdir(worktreePath, { recursive: true });
    await fs.writeFile(path.join(worktreePath, 'test.txt'), 'orphan content');

    // Verify it's NOT in git worktree list anymore
    const { stdout: after } = await execAsync('git worktree list --porcelain', { cwd: repoDir });
    expect(after).not.toContain(worktreePath);

    // But directory exists
    const exists = await fs.access(worktreePath).then(() => true).catch(() => false);
    expect(exists).toBe(true);
  });

  test('recovery checks if branch still exists', async () => {
    const branch = 'forge/branch-check';
    await execAsync(`git branch "${branch}"`, { cwd: repoDir });

    // Branch exists
    let branchExists = false;
    try {
      await execAsync(`git rev-parse --verify "refs/heads/${branch}"`, { cwd: repoDir });
      branchExists = true;
    } catch {
      branchExists = false;
    }
    expect(branchExists).toBe(true);

    // Delete the branch
    await execAsync(`git branch -D "${branch}"`, { cwd: repoDir });

    // Branch no longer exists
    let branchExistsAfter = false;
    try {
      await execAsync(`git rev-parse --verify "refs/heads/${branch}"`, { cwd: repoDir });
      branchExistsAfter = true;
    } catch {
      branchExistsAfter = false;
    }
    expect(branchExistsAfter).toBe(false);
  });

  test('recovery via backup-create-rsync pattern preserves file contents', async () => {
    const branch = 'forge/rsync-test';
    const worktreePath = path.join(tmpDir, 'project-rsync');
    const backupPath = `${worktreePath}.bak`;

    await execAsync(`git branch "${branch}"`, { cwd: repoDir });
    await execAsync(`git worktree add "${worktreePath}" "${branch}"`, { cwd: repoDir });

    // Add untracked file and modify tracked file
    await fs.writeFile(path.join(worktreePath, 'untracked.txt'), 'untracked content');
    await fs.writeFile(path.join(worktreePath, 'README.md'), '# Modified Content');

    // Step 1: Rename to backup
    await fs.rename(worktreePath, backupPath);

    // Verify backup has our files
    const backupContent = await fs.readFile(path.join(backupPath, 'untracked.txt'), 'utf-8');
    expect(backupContent).toBe('untracked content');

    // Step 2: Prune and create fresh worktree
    await execAsync('git worktree prune', { cwd: repoDir });
    await execAsync(`git worktree add "${worktreePath}" "${branch}"`, { cwd: repoDir });

    // Step 3: Rsync from backup (excluding .git)
    await execAsync(`rsync -a --exclude=.git "${backupPath}/" "${worktreePath}/"`, { cwd: repoDir });

    // Step 4: Verify contents preserved
    const restoredUntracked = await fs.readFile(path.join(worktreePath, 'untracked.txt'), 'utf-8');
    expect(restoredUntracked).toBe('untracked content');

    const restoredReadme = await fs.readFile(path.join(worktreePath, 'README.md'), 'utf-8');
    expect(restoredReadme).toBe('# Modified Content');

    // Step 5: Verify it's a valid git worktree
    const { stdout } = await execAsync('git status', { cwd: worktreePath });
    expect(stdout).toContain('On branch');

    // Cleanup
    await fs.rm(backupPath, { recursive: true, force: true });
  });
});

// ── Stale lock detection ────────────────────────────────────

describe('repair: stale lock detection', () => {
  test('detects locked worktree via git worktree list --porcelain', async () => {
    const branch = 'forge/locked-test';
    const worktreePath = path.join(tmpDir, 'project-locked');

    await execAsync(`git branch "${branch}"`, { cwd: repoDir });
    await execAsync(`git worktree add "${worktreePath}" "${branch}"`, { cwd: repoDir });

    // Lock the worktree
    await execAsync(`git worktree lock "${worktreePath}" --reason "test lock"`, { cwd: repoDir });

    // Parse porcelain output to detect lock
    const { stdout } = await execAsync('git worktree list --porcelain', { cwd: repoDir });
    const lines = stdout.split('\n');
    let inOurWorktree = false;
    let isLocked = false;
    for (const line of lines) {
      if (line.startsWith('worktree ') && line.includes(worktreePath)) {
        inOurWorktree = true;
      } else if (line.startsWith('worktree ') && inOurWorktree) {
        break;
      }
      if (inOurWorktree && (line.trim() === 'locked' || line.trim().startsWith('locked '))) {
        isLocked = true;
      }
    }

    expect(isLocked).toBe(true);

    // Unlock
    await execAsync(`git worktree unlock "${worktreePath}"`, { cwd: repoDir });

    // Verify unlocked
    const { stdout: afterUnlock } = await execAsync('git worktree list --porcelain', { cwd: repoDir });
    let stillLocked = false;
    inOurWorktree = false;
    for (const line of afterUnlock.split('\n')) {
      if (line.startsWith('worktree ') && line.includes(worktreePath)) {
        inOurWorktree = true;
      } else if (line.startsWith('worktree ') && inOurWorktree) {
        break;
      }
      if (inOurWorktree && (line.trim() === 'locked' || line.trim().startsWith('locked '))) {
        stillLocked = true;
      }
    }
    expect(stillLocked).toBe(false);
  });
});

// ── Orphaned directory detection ────────────────────────────

describe('repair: orphaned directory detection', () => {
  test('detects sibling directories matching forge naming pattern', async () => {
    const projectName = path.basename(repoDir);
    const parentDir = path.dirname(repoDir);

    // Create an orphaned directory matching the pattern
    const orphanDir = path.join(parentDir, `${projectName}-orphan-spec`);
    await fs.mkdir(orphanDir, { recursive: true });

    const entries = await fs.readdir(parentDir, { withFileTypes: true });
    const forgePrefix = `${projectName}-`;

    const orphaned = entries
      .filter(e => e.isDirectory() && e.name.startsWith(forgePrefix))
      .map(e => path.join(parentDir, e.name));

    expect(orphaned.length).toBeGreaterThanOrEqual(1);
    expect(orphaned).toContain(orphanDir);

    await fs.rm(orphanDir, { recursive: true, force: true });
  });

  test('distinguishes git worktree directories from regular directories', async () => {
    const projectName = path.basename(repoDir);
    const parentDir = path.dirname(repoDir);

    // Create a real worktree (will have .git as a file)
    const branch = 'forge/real-wt';
    const wtPath = path.join(parentDir, `${projectName}-real-wt`);
    await execAsync(`git branch "${branch}"`, { cwd: repoDir });
    await execAsync(`git worktree add "${wtPath}" "${branch}"`, { cwd: repoDir });

    // Create a fake orphan (regular directory, .git is absent)
    const fakePath = path.join(parentDir, `${projectName}-fake-orphan`);
    await fs.mkdir(fakePath, { recursive: true });

    // Check .git existence and type
    const gitPathReal = path.join(wtPath, '.git');
    const statReal = await fs.stat(gitPathReal);
    expect(statReal.isFile()).toBe(true); // Worktree .git is a file pointing to main repo

    const gitPathFake = path.join(fakePath, '.git');
    const fakeExists = await fs.access(gitPathFake).then(() => true).catch(() => false);
    expect(fakeExists).toBe(false);

    // Cleanup
    await execAsync(`git worktree remove "${wtPath}" --force`, { cwd: repoDir });
    await fs.rm(fakePath, { recursive: true, force: true });
  });
});

// ── Dry-run vs fix mode ─────────────────────────────────────

describe('repair: dry-run vs fix behavior', () => {
  test('dry-run detects issues without modifying state', () => {
    const id = makeId();
    insertWorktree(db, {
      id,
      spec_path: 'specs/dryrun.md',
      branch: 'forge/dryrun',
      worktree_path: '/tmp/nonexistent-dryrun',
      status: 'complete',
    });

    // In dry-run mode, the status should NOT be changed
    // (we simulate by not calling updateWorktreeStatus)
    const wt = getWorktree(db, id)!;
    expect(wt.status).toBe('complete');
  });

  test('fix mode updates worktree status for missing directories', () => {
    const id = makeId();
    insertWorktree(db, {
      id,
      spec_path: 'specs/fixme.md',
      branch: 'forge/fixme',
      worktree_path: '/tmp/nonexistent-fixme',
      status: 'running',
    });

    // Fix mode: mark as failed
    updateWorktreeStatus(db, id, 'failed', 'Directory missing from filesystem');

    const wt = getWorktree(db, id)!;
    expect(wt.status).toBe('failed');
    expect(wt.error).toBe('Directory missing from filesystem');
  });
});

// ── Idempotency ─────────────────────────────────────────────

describe('repair: idempotency', () => {
  test('running repair twice produces the same result', () => {
    const id = makeId();
    insertWorktree(db, {
      id,
      spec_path: 'specs/idempotent.md',
      branch: 'forge/idempotent',
      worktree_path: '/tmp/nonexistent-idem',
      status: 'complete',
    });

    // First fix
    updateWorktreeStatus(db, id, 'failed', 'Directory missing from filesystem');
    expect(getWorktree(db, id)!.status).toBe('failed');

    // Second fix -- same result
    updateWorktreeStatus(db, id, 'failed', 'Directory missing from filesystem');
    expect(getWorktree(db, id)!.status).toBe('failed');
  });
});

// ── Summary output ──────────────────────────────────────────

describe('repair: summary format', () => {
  test('formats N checked, N issues found, N fixed', () => {
    const checked = 5;
    const issues = [
      { fixed: true },
      { fixed: false, skipped: true },
      { fixed: true },
    ];

    const fixed = issues.filter(i => i.fixed).length;
    const skipped = issues.filter(i => 'skipped' in i && i.skipped).length;

    const summary = `${checked} worktrees checked, ${issues.length} issues found, ${fixed} fixed`;
    expect(summary).toBe('5 worktrees checked, 3 issues found, 2 fixed');
    expect(skipped).toBe(1);
  });
});
